
// ===== STATE =====
let questions = [], currentQ = 0, score = 0, studentName = "", userAnswers = [];
let timer = null, timeLeft = 60;
const API_URL = 'https://venel11852.app.n8n.cloud/webhook/get-test';
const SIR_IMG = 'data:image/png;base64,';

// ===== INIT =====
document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('hostImgStart').src = SIR_IMG;
  document.getElementById('hostImgQuiz').src = SIR_IMG;
  // Footer image doesn't need dynamic src, it's already set in HTML
  document.getElementById('studentName').addEventListener('keypress', e => { if(e.key==='Enter') initQuiz(); });
  
  // Load question count on page load
  setTimeout(loadQuestionCount, 500); // Small delay to ensure DOM is ready
});

// ===== LOAD QUESTION COUNT =====
async function loadQuestionCount() {
  const display = document.getElementById('totalQuestionsDisplay');
  
  if (!display) {
    console.error('Element totalQuestionsDisplay not found!');
    return;
  }
  
  display.textContent = '...'; // Loading state
  
  try {
    console.log('Fetching questions from:', API_URL);
    const res = await fetch(API_URL);
    console.log('Response status:', res.status);
    
    if (!res.ok) {
      throw new Error(`HTTP error! status: ${res.status}`);
    }
    
    const data = await res.json();
    console.log('Questions received:', data);
    console.log('Total count:', data.length);
    
    if (data && Array.isArray(data) && data.length > 0) {
      display.textContent = data.length;
      console.log('Updated display to:', data.length);
    } else {
      display.textContent = '10'; // Default fallback
      console.warn('No valid questions array, using default 10');
    }
  } catch(err) {
    console.error('Failed to load question count:', err);
    display.textContent = '10'; // Default fallback on error
  }
}

// ===== MODE TOGGLE =====
let isDark = true;
function toggleMode() {
  isDark = !isDark;
  document.documentElement.setAttribute('data-theme', isDark ? 'dark' : 'light');
  document.getElementById('modeIcon').textContent = isDark ? '☀️' : '🌙';
  document.getElementById('modeLabel').textContent = isDark ? 'Light Mode' : 'Dark Mode';
}

// ===== SCREENS =====
function showScreen(id) {
  document.querySelectorAll('.screen').forEach(s => s.classList.remove('active'));
  document.getElementById(id).classList.add('active');
}

// ===== HOST MESSAGES =====
const hostMsgs = [
  "🎤 Think carefully!", "🧠 Are you sure?", "💡 Take your time!",
  "🔥 You've got this!", "🤔 Hmm, tricky one!", "⚡ Stay focused!",
  "🎯 Aim for the top!", "💪 Believe in yourself!", "🌟 You're doing great!",
  "🏆 Go for the win!"
];

function updateHostMsg() {
  const el = document.getElementById('hostBubble');
  el.textContent = hostMsgs[Math.floor(Math.random() * hostMsgs.length)];
}

// ===== START QUIZ =====
async function initQuiz() {
  const inp = document.getElementById('studentName');
  if (!inp.value.trim()) { inp.style.borderColor = '#ff4444'; inp.focus(); return; }
  inp.style.borderColor = '';

  studentName = inp.value.trim();
  document.getElementById('displayName').textContent = studentName;
  document.getElementById('studentAvatar').textContent = studentName[0].toUpperCase();

  const btn = document.getElementById('startBtn');
  btn.innerHTML = '⏳ Loading<span class="loading-dots"></span>';
  btn.disabled = true;

  try {
    const res = await fetch(API_URL);
    questions = await res.json();
    if (!questions.length) throw new Error("No questions");

    // Update the question count display on start screen for next time
    const countDisplay = document.getElementById('totalQuestionsDisplay');
    if (countDisplay) {
      countDisplay.textContent = questions.length;
    }

    currentQ = 0; score = 0; userAnswers = [];
    showScreen('quizScreen');
    renderQuestion();
  } catch(err) {
    alert("❌ Failed to load questions. Check your API connection.");
    btn.innerHTML = '🎯 START THE TEST';
    btn.disabled = false;
  }
}

// ===== TIMER =====
function startTimer() {
  clearInterval(timer);
  timeLeft = 60;
  updateTimerUI();

  timer = setInterval(() => {
    timeLeft--;
    updateTimerUI();
    if (timeLeft <= 0) {
      clearInterval(timer);
      // Auto next
      nextQuestion();
    }
  }, 1000);
}

function updateTimerUI() {
  const arc = document.getElementById('timerArc');
  const txt = document.getElementById('timerText');
  const circumference = 188;
  const offset = circumference - (timeLeft / 60) * circumference;

  arc.style.strokeDashoffset = offset;
  txt.textContent = timeLeft;

  if (timeLeft <= 15) {
    arc.style.stroke = '#ff4444';
    txt.style.color = '#ff4444';
    if (timeLeft <= 10) txt.style.animation = 'timerPulse 0.5s ease-in-out infinite';
  } else if (timeLeft <= 30) {
    arc.style.stroke = '#ff8c00';
    txt.style.color = '#ff8c00';
    txt.style.animation = '';
  } else {
    arc.style.stroke = 'var(--gold)';
    txt.style.color = 'var(--gold)';
    txt.style.animation = '';
  }
}

// ===== RENDER QUESTION =====
const optLetters = ['A', 'B', 'C', 'D'];

function renderQuestion() {
  const q = questions[currentQ];
  const nextBtn = document.getElementById('nextBtn');
  nextBtn.className = 'btn-next';
  nextBtn.textContent = currentQ === questions.length - 1 ? 'FINISH TEST 🏁' : 'NEXT QUESTION ▶';

  document.getElementById('questionText').textContent = q.question;
  document.getElementById('progressFill').style.width = `${(currentQ / questions.length) * 100}%`;
  document.getElementById('qCount').textContent = `${currentQ + 1}/${questions.length}`;

  const grid = document.getElementById('optionsGrid');
  grid.innerHTML = '';

  for (let i = 1; i <= 4; i++) {
    const txt = q[`option${i}`];
    if (!txt) continue;
    const div = document.createElement('div');
    div.className = 'option-btn';
    div.innerHTML = `<div class="option-letter">${optLetters[i-1]}</div><div class="option-text">${txt}</div>`;
    div.onclick = () => selectOption(div, txt);
    grid.appendChild(div);
  }

  updateHostMsg();
  startTimer();
}

// ===== SELECT OPTION =====
function selectOption(el, text) {
  document.querySelectorAll('.option-btn').forEach(o => o.classList.remove('selected'));
  el.classList.add('selected');
  userAnswers[currentQ] = text;
  const nextBtn = document.getElementById('nextBtn');
  nextBtn.classList.add('enabled');
}

// ===== NEXT QUESTION =====
function nextQuestion() {
  clearInterval(timer);

  if (currentQ < questions.length - 1) {
    currentQ++;
    renderQuestion();
  } else {
    finishQuiz();
  }
}

// ===== FINISH QUIZ =====
function finishQuiz() {
  clearInterval(timer);
  score = 0;
  let skipped = 0;

  questions.forEach((q, i) => {
    if (!userAnswers[i]) { skipped++; return; }
    if (userAnswers[i] === q.answer) score++;
  });

  const wrong = questions.length - score - skipped;
  const pct = Math.round((score / questions.length) * 100);

  document.getElementById('scorePercent').textContent = `${pct}%`;
  document.getElementById('rCorrect').textContent = score;
  document.getElementById('rWrong').textContent = wrong;
  document.getElementById('rSkipped').textContent = skipped;
  document.getElementById('resultName').textContent = `Great effort, ${studentName}! 🌟`;

  if (pct >= 80) {
    document.getElementById('resultEmoji').textContent = '🏆';
    document.getElementById('resultTitle').textContent = 'Excellent Performance!';
  } else if (pct >= 50) {
    document.getElementById('resultEmoji').textContent = '👍';
    document.getElementById('resultTitle').textContent = 'Good Effort!';
  } else {
    document.getElementById('resultEmoji').textContent = '📚';
    document.getElementById('resultTitle').textContent = 'Keep Practicing!';
  }

  showScreen('resultScreen');
  if (pct >= 50) setTimeout(celebrate, 600);
}

// ===== RESTART (PROPER FIX) =====
function restartTest() {
  clearInterval(timer);
  questions = []; currentQ = 0; score = 0; userAnswers = []; timeLeft = 60;

  // Reset form
  document.getElementById('studentName').value = '';
  document.getElementById('startBtn').innerHTML = '🎯 START THE TEST';
  document.getElementById('startBtn').disabled = false;

  showScreen('startScreen');
}

// ===== CONFETTI CELEBRATION =====
let confettiAnimFrame;
let particles = [];

function celebrate() {
  const canvas = document.getElementById('confettiCanvas');
  const ctx = canvas.getContext('2d');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;

  cancelAnimationFrame(confettiAnimFrame);
  particles = [];

  const colors = ['#f5c518','#ff8c00','#ff4444','#00ff88','#4488ff','#ff44ff','#ffffff','#ffaa00'];
  const shapes = ['circle','rect','balloon','star'];

  for (let i = 0; i < 160; i++) {
    particles.push({
      x: Math.random() * canvas.width,
      y: -20 - Math.random() * 200,
      size: 6 + Math.random() * 14,
      color: colors[Math.floor(Math.random() * colors.length)],
      shape: shapes[Math.floor(Math.random() * shapes.length)],
      vx: (Math.random() - 0.5) * 4,
      vy: 2 + Math.random() * 5,
      rot: Math.random() * 360,
      rotV: (Math.random() - 0.5) * 8,
      alpha: 1,
      sway: Math.random() * 0.05,
      swayPhase: Math.random() * Math.PI * 2,
      life: 1
    });
  }

  // Rockets
  for (let i = 0; i < 5; i++) {
    particles.push({
      x: 100 + Math.random() * (canvas.width - 200),
      y: canvas.height + 20,
      size: 20,
      color: colors[Math.floor(Math.random() * colors.length)],
      shape: 'rocket',
      vx: (Math.random() - 0.5) * 2,
      vy: -(8 + Math.random() * 6),
      rot: 0, rotV: 0, alpha: 1, sway: 0, swayPhase: 0, life: 1,
      exploded: false,
      explodeY: canvas.height * (0.2 + Math.random() * 0.4)
    });
  }

  let frame = 0;
  function draw() {
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    let alive = false;

    particles.forEach(p => {
      if (p.alpha <= 0) return;
      alive = true;
      ctx.save();
      ctx.globalAlpha = p.alpha;
      ctx.translate(p.x, p.y);

      if (p.shape === 'rocket') {
        if (!p.exploded) {
          ctx.font = `${p.size}px serif`;
          ctx.fillText('🚀', -p.size/2, p.size/2);
          p.x += p.vx;
          p.y += p.vy;
          p.vy += 0.1; // gravity
          if (p.y <= p.explodeY) {
            p.exploded = true;
            // Burst confetti
            for (let j = 0; j < 30; j++) {
              const angle = (j / 30) * Math.PI * 2;
              const speed = 3 + Math.random() * 5;
              particles.push({
                x: p.x, y: p.y,
                size: 5 + Math.random() * 8,
                color: colors[Math.floor(Math.random() * colors.length)],
                shape: ['circle','rect','star'][Math.floor(Math.random()*3)],
                vx: Math.cos(angle) * speed,
                vy: Math.sin(angle) * speed - 2,
                rot: 0, rotV: (Math.random()-0.5)*10, alpha: 1,
                sway: 0, swayPhase: 0, life: 1
              });
            }
            p.alpha = 0;
          }
        }
      } else if (p.shape === 'balloon') {
        ctx.font = `${p.size * 1.6}px serif`;
        ctx.rotate(p.rot * Math.PI / 180);
        ctx.fillText('🎈', -p.size/2, p.size/2);
        p.x += p.vx + Math.sin(frame * p.sway + p.swayPhase) * 1;
        p.y -= 1.5;
        p.rot += p.rotV * 0.3;
        p.alpha -= 0.004;
      } else {
        ctx.rotate(p.rot * Math.PI / 180);
        ctx.fillStyle = p.color;
        if (p.shape === 'circle') {
          ctx.beginPath();
          ctx.arc(0, 0, p.size/2, 0, Math.PI*2);
          ctx.fill();
        } else if (p.shape === 'rect') {
          ctx.fillRect(-p.size/2, -p.size/4, p.size, p.size/2);
        } else if (p.shape === 'star') {
          drawStar(ctx, 0, 0, 5, p.size/2, p.size/4);
        }
        p.x += p.vx + Math.sin(frame * p.sway + p.swayPhase) * 0.5;
        p.y += p.vy;
        p.vy += 0.12;
        p.rot += p.rotV;
        if (p.y > canvas.height * 0.7) p.alpha -= 0.02;
      }

      ctx.restore();
    });

    frame++;
    if (alive && frame < 300) confettiAnimFrame = requestAnimationFrame(draw);
    else { ctx.clearRect(0, 0, canvas.width, canvas.height); }
  }

  draw();
}

function drawStar(ctx, cx, cy, spikes, outerR, innerR) {
  let rot = (Math.PI / 2) * 3, step = Math.PI / spikes;
  ctx.beginPath();
  ctx.moveTo(cx, cy - outerR);
  for (let i = 0; i < spikes; i++) {
    ctx.lineTo(cx + Math.cos(rot) * outerR, cy + Math.sin(rot) * outerR);
    rot += step;
    ctx.lineTo(cx + Math.cos(rot) * innerR, cy + Math.sin(rot) * innerR);
    rot += step;
  }
  ctx.lineTo(cx, cy - outerR);
  ctx.closePath();
  ctx.fill();
}

window.addEventListener('resize', () => {
  const canvas = document.getElementById('confettiCanvas');
  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
});
